-- card_product: source_card_id=2687, name=카드의정석 SHOPPING+
-- mock_bin collision guard: insert only when mock_bin is unused or already belongs to the same source_card_id.
INSERT INTO card_product (
  mock_bin, card_company, card_name, card_type, annual_fee, image_url, source_card_id, source_url, created_at, updated_at
)
SELECT '850002', '우리카드', '카드의정석 SHOPPING+', 'CREDIT', 10000, 'https://d1c5n4ri2guedi.cloudfront.net/card/2687/card_img/33239/2687card.png', '2687', 'https://www.card-gorilla.com/card/detail/2687', NOW(), NOW()
FROM DUAL
WHERE NOT EXISTS (
    SELECT 1
    FROM card_product
    WHERE source_card_id = '2687'
  )
  AND NOT EXISTS (
    SELECT 1
    FROM card_product
    WHERE mock_bin = '850002'
      AND source_card_id <> '2687'
  );
UPDATE card_product
SET card_company = '우리카드',
    card_name = '카드의정석 SHOPPING+',
    card_type = 'CREDIT',
    annual_fee = 10000,
    image_url = 'https://d1c5n4ri2guedi.cloudfront.net/card/2687/card_img/33239/2687card.png',
    source_url = 'https://www.card-gorilla.com/card/detail/2687',
    updated_at = NOW()
WHERE source_card_id = '2687';
SET @card_product_id_2687 = (
  SELECT card_product_id
  FROM card_product
  WHERE source_card_id = '2687'
  LIMIT 1
);

