  benefit_id, min_prev_month_usage, max_prev_month_usage, rate, flat_amount, max_benefit_per_use,
  daily_limit_count, daily_limit_amount, monthly_limit_count, monthly_limit_amount,
  yearly_limit_count, yearly_limit_amount, tier_desc, created_at, updated_at
)
SELECT @benefit_id_2553_1, 0, NULL, 0.100, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '[UNIT_REWARD type=MILE base_value=1 spend=1000 reward=1 rate=0.100] 원문: 1천원당 SKYPASS 1마일리지 | 전체 원문: SKYPASS 최대 2마일리지 적립 이용금액 1천원당 SKYPASS 1마일리지 적립 ※ 전월실적 조건 없음 - 추가 월 적립한도는 본인+가족카드 합산 기준이며, 추가 적립한도 초과 이용금액은 기본 적립혜택만 제공 (추가 월 적립한도 1천 마일 적용) 예시) 본인카드 해외 50만원 이용 시 1,000마일 적립 (기본 500마일 + 추가 500마일) 가족카드 해외 70만원 이용 시 1,200마일 적립 (기본 700마일 + 추가 500마일) ※ 해외 이용금액은 우리카드 전산상 해외매출 분류된 경우에 한하며, 당사 매출표 접수일 기준으로 반영됨', NOW(), NOW()
FROM DUAL
WHERE @benefit_id_2553_1 IS NOT NULL
  AND NOT EXISTS (
    SELECT 1
    FROM card_benefit_tier
    WHERE benefit_id = @benefit_id_2553_1
      AND min_prev_month_usage = 0
  );

